#include <bits/stdc++.h>
#define int long long
using namespace std;
int l, r;
int book[10000005];
int k, ans;
int mod = 1e9 + 7, i, j;
signed main () {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	cin >> l >> r;
	for (i = l; i <= r; i++) {
		if (book[i] == 0) {
			for (k++, j = i * 2; j <= r; j += i) {
				book[j] = 1;
			}
		}
	}
	ans = k;
	for (i = 1; i <= r - l + 2; i++) {
		if (i != k + 1) {
			ans = ans * i % mod;
		}
	}
	cout << ans;
	return 0;
}
